%[text] %[text:anchor:T_946a] # Coupled Pendulum's Resonate
%[text:tableOfContents]{"heading":"**Table of Contents**"}
%[text] %[text:anchor:H_28e9] ## 
%[text] %[text:anchor:H_163e] ## 
